309	function truncateTail(text, maxBytes) {
310	  const value = String(text ?? "");
311	  const bytes = Buffer.byteLength(value, "utf8");
312	  if (bytes <= maxBytes) return { text: value, truncated: false, bytes };
313	  const marker = `\n[truncated: kept tail, ${bytes - maxBytes} bytes omitted]\n`;
314	  const markerBytes = Buffer.byteLength(marker, "utf8");
315	  let tail = value.slice(Math.max(0, value.length - (maxBytes - markerBytes)));
316	  while (Buffer.byteLength(tail, "utf8") + markerBytes > maxBytes) tail = tail.slice(1);
317	  return { text: `${marker}${tail}`, truncated: true, bytes };
318	}
