146	export async function spawnWithInput(command, args, options = {}) {
147	  const { cwd = process.cwd(), input, signal, timeoutMs = DEFAULT_TIMEOUT_MS, env: envOverrides, dropEnv } = options;
148	  let env;
149	  if (envOverrides || (dropEnv && dropEnv.length > 0)) {
150	    env = { ...process.env, ...(envOverrides ?? {}) };
151	    for (const key of dropEnv ?? []) delete env[key];
152	  }
153	  return await new Promise((resolve) => {
154	    const child = spawn(command, args, { cwd, env, stdio: ["pipe", "pipe", "pipe"], shell: false });
155	    let stdout = "";
156	    let stderr = "";
157	    let truncated = false;
158	    let settled = false;
159	    let timedOut = false;
160	    let timeout;
161	
162	    const append = (target, chunk) => {
163	      const text = chunk.toString();
164	      if (target === "stdout") stdout += text;
165	      else stderr += text;
166	      if (Buffer.byteLength(stdout, "utf8") > MAX_CAPTURE_BYTES) {
167	        stdout = truncateTail(stdout, MAX_CAPTURE_BYTES).text;
168	        truncated = true;
169	      }
170	      if (Buffer.byteLength(stderr, "utf8") > MAX_CAPTURE_BYTES) {
171	        stderr = truncateTail(stderr, MAX_CAPTURE_BYTES).text;
172	        truncated = true;
173	      }
174	    };
175	
176	    const finish = (exitCode, sig) => {
177	      if (settled) return;
178	      settled = true;
179	      clearTimeout(timeout);
180	      if (signal) signal.removeEventListener("abort", abortHandler);
181	      resolve({ stdout, stderr, exitCode, signal: sig, timedOut, truncated });
182	    };
183	
184	    const forceKillIfAlive = () => {
185	      if (child.exitCode === null && child.signalCode === null) child.kill("SIGKILL");
186	    };
187	
188	    const abortHandler = () => {
189	      child.kill("SIGTERM");
190	      setTimeout(forceKillIfAlive, 3000).unref?.();
191	    };
192	
193	    if (signal) {
194	      if (signal.aborted) abortHandler();
195	      else signal.addEventListener("abort", abortHandler, { once: true });
196	    }
197	
198	    timeout = setTimeout(() => {
199	      timedOut = true;
200	      child.kill("SIGTERM");
201	      setTimeout(forceKillIfAlive, 3000).unref?.();
202	    }, timeoutMs);
203	    timeout.unref?.();
204	
205	    child.stdout.on("data", (chunk) => append("stdout", chunk));
206	    child.stderr.on("data", (chunk) => append("stderr", chunk));
207	    child.on("error", (error) => {
208	      stderr += `\n[spawn error] ${error.message}`;
209	      finish(127, null);
210	    });
211	    child.on("close", (code, sig) => finish(code ?? 0, sig));
