213	    // A child that exits before consuming stdin (bad flag, login failure) raises EPIPE here;
214	    // without a listener that is an uncaughtException that kills the host process.
215	    child.stdin.on("error", (error) => append("stderr", `\n[stdin error] ${error.message}`));
216	    if (input !== undefined) child.stdin.end(input);
217	    else child.stdin.end();
218	  });
219	}
