184	    throw new Error("Nested ConsensFlow runs are disabled inside participant subprocesses.");
185	  }
186	  await ensureCfDirs(cwd);
187	  const parsed = parseOptions(tokens);
188	  const positional = [...parsed.positional];
189	  const ref = positional.shift();
190	  if (!ref || !ref.startsWith("@")) {
191	    throw new Error("Usage: /consensflow:cf @name <prompt> — or via the Bash tool: run @name <prompt> [--prompt-file <file>] [--context <note>] [--no-handoff] [--timeout-ms <ms>] [--json]");
192	  }
193	  if (positional[0]?.startsWith("@")) {
194	    throw new Error("ConsensFlow sends to one participant at a time. Ask one, read its answer, then ask another.");
195	  }
196	
197	  const participant = await getParticipant(cwd, ref);
198	  if (!participant) {
199	    const known = (await loadParticipants(cwd)).map((p) => `@${p.id}`).join(", ") || "none configured — add one with `/consensflow:participants add <preset>` (see `/consensflow:presets`)";
