201	  }
202	
203	  let prompt = positional.join(" ");
204	  if (stringFlag(parsed.flags.prompt) !== undefined) prompt = String(parsed.flags.prompt);
205	  if (stringFlag(parsed.flags["prompt-file"]) !== undefined) prompt = await fs.readFile(String(parsed.flags["prompt-file"]), "utf8");
206	  prompt = prompt.trim();
207	  if (!prompt) throw new Error(`Prompt is required after @${participant.id} (inline, --prompt, or --prompt-file).`);
208	
209	  // Image participants bypass the CLI runner: prompt-only (no packet/handoff), Codex backend.
210	  if (participant.kind === "image") return await runImageParticipant(cwd, participant, prompt, parsed.flags);
211	
212	  // Only an unexpectedly-empty handoff is surfaced in the run output — a silently-missing session
213	  // stash would otherwise look identical to a full handoff from the participant's answer alone.
214	  let handoff = "";
215	  let handoffSummary = "skipped (--no-handoff)";
216	  if (flagBool(parsed.flags, "handoff") ?? true) {
217	    handoff = stringFlag(parsed.flags["handoff-file"]) !== undefined
218	      ? await fs.readFile(String(parsed.flags["handoff-file"]), "utf8")
219	      : await collectHandoff(cwd);
220	    handoffSummary = handoff.trim()
221	      ? `attached (${Math.max(1, Math.round(Buffer.byteLength(handoff, "utf8") / 1024))} KB)`
