223	  }
224	
225	  const effective = participantForKind(participant, "ask");
226	  const packet = await createPacket({ cwd, participant: effective, kind: "ask", task: prompt, extraContext: stringFlag(parsed.flags.context), handoff });
227	  const result = await runParticipant({ cwd, participant: effective, packet, kind: "ask", timeoutMs: parsed.flags["timeout-ms"] });
228	  result.handoffSummary = handoffSummary;
229	
230	  if (parsed.flags.json === true) {
231	    console.log(JSON.stringify(result, null, 2));
232	    return;
233	  }
234	  console.log(renderRunResult(result));
235	}
