 35	export function buildRunnerInvocation(participant, packetPath, cwd) {
 36	  const p = participant;
 37	  switch (p.kind) {
 38	    case "pi": {
 39	      const args = ["--mode", "json", "--no-session", "--no-extensions"];
 40	      if (p.skillsPolicy === "none" || p.skillsPolicy === "explicit") args.push("--no-skills");
 41	      if (p.skillsPolicy === "explicit") {
