 45	      args.push("--thinking", p.thinking ?? "off");
 46	      args.push("--tools", toolsForPi(p.toolsPolicy), "-p", "Follow the ConsensFlow packet provided on stdin. Return only the requested output.");
 47	      return { command: "pi", args, stdinMode: "packet", cwd };
 48	    }
 49	    case "claude-code": {
 50	      const args = ["-p", "Follow the ConsensFlow packet provided on stdin. Return only the requested output.", "--output-format", "json", "--no-session-persistence", "--allowedTools", claudeAllowedTools(p.toolsPolicy)];
 51	      if (p.toolsPolicy === "readonly") args.push("--disallowedTools", CLAUDE_READONLY_DISALLOWED);
 52	      if (p.model) args.push("--model", p.model);
 53	      if (p.effort) args.push("--effort", p.effort);
 54	      if (p.maxTurns) args.push("--max-turns", String(p.maxTurns));
 55	      if (p.toolsPolicy === "full-auto") args.push("--dangerously-skip-permissions");
 56	      // Without the env key, claude falls back to the subscription login; with it, it silently
 57	      // bills the API. Strip it so participant runs always ride the configured login.
 58	      return { command: "claude", args, stdinMode: "packet", cwd, dropEnv: ["ANTHROPIC_API_KEY"] };
 59	    }
 60	    case "codex": {
 61	      const args = ["exec", "--json", "--ephemeral", "--skip-git-repo-check", "--ignore-user-config", "--ignore-rules", "--sandbox", codexSandbox(p.toolsPolicy), "-C", cwd];
