 91	export async function runParticipant(input) {
 92	  const { cwd, participant, packet, kind = "ask", signal } = input;
 93	  await ensureCfDirs(cwd);
 94	  const runId = input.runId ?? createId(kind);
 95	  const runDir = path.join(runsRoot(cwd), runId);
 96	  await fs.mkdir(runDir, { recursive: true });
 97	  const packetPath = path.join(runDir, "packet.md");
 98	  await fs.writeFile(packetPath, packet, "utf8");
 99	
100	  const invocationCwd = participant.cwd ? resolveInside(cwd, participant.cwd) : path.resolve(cwd);
101	  const invocation = buildRunnerInvocation(participant, packetPath, invocationCwd);
102	  const startedAt = nowIso();
103	  const procResult = await spawnWithInput(invocation.command, invocation.args, {
104	    cwd: invocation.cwd,
105	    input: invocation.stdinMode === "packet" ? packet : undefined,
106	    env: invocation.env,
107	    dropEnv: invocation.dropEnv,
108	    signal,
109	    timeoutMs: effectiveTimeoutMs(participant, input.timeoutMs),
110	  });
111	  const endedAt = nowIso();
112	
113	  await fs.writeFile(path.join(runDir, "stdout.txt"), procResult.stdout, "utf8");
114	  await fs.writeFile(path.join(runDir, "stderr.txt"), procResult.stderr, "utf8");
115	  const normalized = normalizeProcessOutput(participant.kind, procResult.stdout, procResult.stderr);
116	  const result = {
117	    schemaVersion: 1,
118	    runId,
119	    runDir,
120	    packetPath,
121	    kind,
122	    participant,
123	    invocation: { command: invocation.command, args: invocation.args, cwd: invocation.cwd },
124	    startedAt,
125	    endedAt,
126	    exitCode: procResult.exitCode,
127	    timedOut: procResult.timedOut,
128	    signal: procResult.signal,
129	    output: normalized.output,
130	    rawOutputTruncated: procResult.truncated,
131	    stderr: truncateText(procResult.stderr, 64 * 1024).text,
132	  };
133	  await fs.writeFile(path.join(runDir, "result.json"), `${JSON.stringify(result, null, 2)}\n`, "utf8");
134	  await recordLatestRun(cwd, result);
135	  return result;
136	}
