221	        for (let i = parsed.length - 1; i >= 0; i -= 1) {
222	          const event = parsed[i];
223	          if (typeof event?.result === "string") return { output: event.result, parsed };
224	          if (typeof event?.message?.content === "string") return { output: event.message.content, parsed };
