229	      return { output: parsed.result ?? parsed.structured_output ?? JSON.stringify(parsed, null, 2), parsed };
230	    }
231	  }
232	
233	  const lines = trimmed.split(/\r?\n/).filter(Boolean);
234	  const parsedLines = lines.map((line) => tryParseJson(line)).filter(Boolean);
235	  if (parsedLines.length > 0) {
236	    const final = findFinalJsonOutput(kind, parsedLines);
237	    if (final) return { output: final, parsed: parsedLines };
238	  }
239	
240	  return { output: trimmed, parsed: null };
241	}
