254	      const event = events[i];
255	      if (event.type === "agent_end" && Array.isArray(event.messages)) {
256	        const message = [...event.messages].reverse().find((entry) => entry?.role === "assistant");
257	        const text = contentToText(message?.content);
258	        if (text) return text;
259	      }
260	      if ((event.type === "message_end" || event.type === "turn_end") && event.message?.role === "assistant") {
261	        const text = contentToText(event.message.content);
262	        if (text) return text;
263	      }
264	      if (event.assistantMessageEvent?.type === "text_end" && typeof event.assistantMessageEvent.content === "string") {
265	        return event.assistantMessageEvent.content;
266	      }
267	    }
268	  }
269	
270	  if (kind === "codex") {
271	    for (let i = events.length - 1; i >= 0; i -= 1) {
272	      const event = events[i];
273	      const message = event.message ?? event.msg ?? event.item;
274	      if (typeof event.result === "string") return event.result;
275	      if (typeof event.output === "string") return event.output;
276	      if (typeof message === "string") return message;
277	      if (typeof message?.text === "string") return message.text;
278	      if (message?.content) return contentToText(message.content);
279	    }
280	  }
281	
282	  if (kind === "opencode") {
283	    for (let i = events.length - 1; i >= 0; i -= 1) {
284	      const event = events[i];
285	      if (typeof event.text === "string") return event.text;
286	      if (typeof event.message === "string") return event.message;
287	      if (event.message?.content) return contentToText(event.message.content);
288	      if (event.part?.text) return event.part.text;
289	    }
290	  }
291	
292	  for (let i = events.length - 1; i >= 0; i -= 1) {
293	    const event = events[i];
294	    if (typeof event.result === "string") return event.result;
295	    if (typeof event.output === "string") return event.output;
296	    if (typeof event.text === "string") return event.text;
297	  }
298	  return null;
299	}
