301	function truncateTail(text, maxBytes) {
302	  const value = String(text ?? "");
303	  const bytes = Buffer.byteLength(value, "utf8");
304	  if (bytes <= maxBytes) return { text: value, truncated: false, bytes };
305	  const marker = `\n[truncated: kept tail, ${bytes - maxBytes} bytes omitted]\n`;
306	  const markerBytes = Buffer.byteLength(marker, "utf8");
307	  let tail = value.slice(Math.max(0, value.length - (maxBytes - markerBytes)));
308	  while (Buffer.byteLength(tail, "utf8") + markerBytes > maxBytes) tail = tail.slice(1);
309	  return { text: `${marker}${tail}`, truncated: true, bytes };
310	}
311	
312	function contentToText(content) {
313	  if (typeof content === "string") return content;
314	  if (!Array.isArray(content)) return JSON.stringify(content);
315	  return content
316	    .map((part) => {
317	      if (typeof part === "string") return part;
318	      if (part?.type === "text") return part.text;
319	      if (typeof part?.text === "string") return part.text;
320	      return "";
321	    })
322	    .filter(Boolean)
323	    .join("\n");
324	}

