119	// Register a dedicated `/<id>` command per configured participant so you can talk to them
120	// directly (e.g. `/zeus ...`), instead of only the generic `/cf @zeus ...`. Participants are
121	// global, so this runs once at load; new participants get their command after `/reload`.
122	async function registerParticipantCommands(pi: ExtensionAPI) {
123	  let participants: any[] = [];
124	  try {
125	    participants = await loadParticipants(process.cwd());
126	  } catch {
127	    return;
128	  }
129	  const taken = new Set(RESERVED_COMMAND_NAMES);
130	  try {
131	    for (const command of pi.getCommands()) taken.add(command.name);
132	  } catch {
133	    // getCommands may be unavailable mid-load; reserved set still guards the obvious clashes.
134	  }
135	  for (const participant of participants) {
136	    const name = participant.id;
137	    if (taken.has(name)) continue; // never shadow a built-in or another participant's command
138	    try {
139	      pi.registerCommand(name, {
140	        description: `ConsensFlow: ask @${participant.id}${participant.model ? ` (${participant.kind} ${participant.model})` : ""}`,
141	        handler: async (args, ctx) => {
142	          const prompt = String(args ?? "").trim();
143	          if (!prompt) {
144	            ctx.ui.notify(`Usage: /${name} <prompt>`, "warning");
145	            return;
146	          }
147	          try {
148	            await ensureCfDirs(ctx.cwd);
149	            await handleParticipantPrompt({ participant: participant.id, prompt }, ctx, pi, ctx.signal);
150	          } catch (error) {
151	            reportCfError(pi, ctx, error);
152	          }
153	        },
154	      });
155	      taken.add(name);
156	    } catch {
157	      // Skip on duplicate/registration error; @mention and /cf remain available as fallbacks.
158	    }
159	  }
160	}
