162	async function handleCf(args: string, ctx: any, pi: ExtensionAPI) {
163	  try {
164	    await ensureCfDirs(ctx.cwd);
165	    const tokens = tokenize(args);
166	    if (tokens.length === 0) return await handleStatus(ctx, pi);
167	
168	    const known = await knownParticipantKeys(ctx.cwd);
169	    const directPrompt = parseParticipantPrompt(tokens, known);
170	    if (directPrompt) return await handleParticipantPrompt(directPrompt, ctx, pi, ctx.signal);
171	
172	    const command = tokens.shift() ?? "status";
173	    switch (command) {
174	      case "status":
175	      case "state":
176	        return await handleStatus(ctx, pi);
177	      case "doctor":
178	        return await handleDoctor(ctx, pi);
179	      case "participants":
180	      case "participant":

300	      const name = stringFlag(parsed.flags.name) ?? presetRef;
301	      if (!name) throw new Error("Custom participant needs a name: /cf participants add --name <name> --kind <kind> --model <model> ...");
302	      const participant = await upsertParticipant(ctx.cwd, customParticipantInput(name, parsed.flags));
303	      ctx.ui.notify(`Saved @${participant.id}`, "info");
304	      return sendCfMessage(pi, `Saved custom participant @${participant.id} in ${configRoot()}.\n\n${formatParticipantLine(participant)}\n\n${reloadHint()}`, { participant, configRoot: configRoot() });
305	    }
306	
307	    if (presetRef) {
308	      throw new Error(`Unknown preset: ${presetRef}\n\nPresets: ${listPresetIds().join(", ")} (rename any with --name).\n\nOr create a custom participant:\n  /cf participants add --name <name> --kind <pi|claude-code|codex|opencode|image> --model <model> [--effort <e>] [--tools <readonly|workspace-write|full-auto>]`);
309	    }
310	    throw new Error(addUsage());
311	  }
312	  throw new Error("Usage: /cf participants list|presets|add|show|remove");
313	}
