315	async function handleParticipantPrompt(parsed: ParticipantPrompt, ctx: any, pi: ExtensionAPI, signal?: AbortSignal) {
316	  if (parsed.error) throw new Error(parsed.error);
317	  const participant = await getParticipant(ctx.cwd, parsed.participant);
318	  if (!participant) throw new Error(`Unknown participant: @${parsed.participant}`);
319	  if (participant.kind === "image") return await runImageParticipant(participant, parsed.prompt, ctx, pi, signal);
320	  ctx.ui.notify(`Asking @${participant.id}...`, "info");
321	  const handoff = collectHandoff(ctx);
322	  const result = await runNamedParticipant({
323	    cwd: ctx.cwd,
324	    participantRef: participant,
325	    kind: "ask",
326	    task: parsed.prompt,
327	    handoff,
328	    signal,
329	  });
330	  result.handoffSummary = summarizeHandoff(handoff, true);
331	  // Record the prompt in details so later participants' handoffs can reconstruct this exchange
332	  // (the @mention input was "handled" and is never stored as a normal session message).
333	  sendCfMessage(pi, renderRunResult(result), { ...result, prompt: parsed.prompt });
334	}
