391	// Pull the current resolved session transcript on-demand from the read-only session manager and
392	// serialize it for the participant handoff. On-demand (not cached) so it stays correct across
393	// fork / tree navigation / session switch. Degrades to "" if unavailable.
394	function collectHandoff(ctx: any): string {
395	  try {
396	    const sessionManager = ctx?.sessionManager;
397	    if (!sessionManager || typeof sessionManager.getBranch !== "function") return "";
398	    return serializeTranscript(sessionManager.getBranch(), { maxBytes: HANDOFF_MAX_BYTES });
399	  } catch {
400	    return "";
401	  }
