404	type ParticipantPrompt = { participant: string; prompt: string; error?: undefined } | { participant?: undefined; prompt?: undefined; error: string };
405	
406	// Tokenize a typed line and decide whether it addresses one participant. When the line contains
407	// any `@token`, load the configured participants so a single non-leading mention (`hi @zeus`)
408	// routes only when it names a real participant — a stray `@types/node` is left for the lead.
409	async function parseTypedPrompt(text: string, ctx: any): Promise<ParticipantPrompt | null> {
410	  const trimmed = String(text ?? "").trim();
411	  if (!trimmed || trimmed.startsWith("/")) return null;
412	  const tokens = tokenize(trimmed);
413	  if (!tokens.some((token) => token.startsWith("@"))) return null;
414	  return parseParticipantPrompt(tokens, await knownParticipantKeys(ctx.cwd));
415	}
