417	// Slugified ids + names of every configured participant, matching getParticipant's resolution.
418	async function knownParticipantKeys(cwd: string): Promise<Set<string>> {
419	  const participants = await loadParticipants(cwd).catch(() => []);
420	  return new Set((participants as any[]).flatMap((p) => [p.id, slugify(p.name)]).filter(Boolean));
421	}
