427	function assertAllowedFlags(flags: Record<string, unknown>, allowed: string[], context: string) {
428	  const allowedSet = new Set(allowed);
429	  const rejected = Object.keys(flags).filter((flag) => !allowedSet.has(flag));
430	  if (rejected.length > 0) {
431	    throw new Error(`Unsupported ${context} option(s): ${rejected.map((flag) => `--${flag}`).join(", ")}. Allowed: ${allowed.map((flag) => `--${flag}`).join(", ")}.`);
432	  }
433	}
