513	function formatParticipantLine(p: any) {
514	  const model = p.model ? ` model=${p.model}` : "";
515	  const effort = p.effort ? ` effort=${p.effort}` : p.thinking ? ` thinking=${p.thinking}` : "";
516	  const cwd = p.cwd ? ` cwd=${p.cwd}` : "";
517	  const skills = p.kind === "pi" ? ` skills=${p.skillsPolicy ?? "default"}` : "";
518	  const preset = p.preset ? ` preset=${p.preset}` : "";
519	  // effectiveToolsPolicy normalizes a missing policy to the readonly default.
520	  const head = `- @${p.id} (${p.kind}${model}${effort}${cwd}${skills}${preset}) tools=${effectiveToolsPolicy(p)}`;
521	  return p.description ? `${head}\n    ${p.description}` : head;
