524	// The run output reports what context rode along: a silently-empty handoff looks identical to a
525	// full one from the participant's answer alone.
526	function summarizeHandoff(handoff: string, included: boolean) {
527	  if (!included) return "skipped (includeHandoff=false)";
528	  if (!String(handoff ?? "").trim()) return "empty — no session history to hand off";
529	  return `attached (${Math.max(1, Math.round(Buffer.byteLength(handoff, "utf8") / 1024))} KB)`;
530	}
