532	// Just the answer on a clean read-only run. Diagnostics appear only when they matter: the run
533	// failed, the handoff was unexpectedly empty, or the participant could have written to the
534	// workspace. Full metadata stays in result.json and the message details.
535	function renderRunResult(result: any) {
536	  const writeCapable = effectiveToolsPolicy(result.participant) !== "readonly";
537	  const lines = [`# @${result.participant.id}`];
538	  if (result.exitCode !== 0 || result.timedOut) {
539	    lines.push("", `Run failed: exit ${result.exitCode}${result.timedOut ? " (timed out)" : ""} — artifacts: ${result.runDir}`);
540	  }
541	  if (result.handoffSummary?.startsWith("empty")) lines.push("", `Handoff: ${result.handoffSummary}`);
542	  if (writeCapable) lines.push("", "> Write-capable run: this participant could edit files and run commands. Inspect what changed in the workspace (e.g. `git status` / `git diff` in a repo) and review it before keeping or building on it.");
543	  lines.push("", result.output);
544	  return lines.join("\n");
545	}
