561	  return `# ConsensFlow help
562	
563	Natural-language prompts to one participant at a time. Each participant gets the current
564	session as a handoff plus your prompt, and answers conversationally.
565	
566	Ask a participant (all equivalent):
567	
568	\`\`\`text
569	/zeus What do you think about this approach?      # dedicated per-participant command
570	@zeus What do you think about this approach?      # bare mention

220	  const claude = buildRunnerInvocation({ kind: "claude-code", toolsPolicy: "readonly" }, "/tmp/packet.md", "/repo");
221	  assert.ok(claude.args.includes("Read,Grep,Glob"));
222	  const denyIndex = claude.args.indexOf("--disallowedTools");
223	  assert.ok(denyIndex >= 0);
224	  assert.match(claude.args[denyIndex + 1], /Bash/);
225	  assert.match(claude.args[denyIndex + 1], /Edit/);
226	  assert.match(claude.args[denyIndex + 1], /Write/);
227	  // The CC-specific recursion/stomp guard: claude children skip plugin/hook/skill discovery.
228	  assert.ok(claude.args.includes("--bare"));
229	  assert.ok(claude.args.includes("--no-session-persistence"));
230	  const claudeWrite = buildRunnerInvocation({ kind: "claude-code", toolsPolicy: "workspace-write" }, "/tmp/packet.md", "/repo");
231	  assert.equal(claudeWrite.args.includes("--disallowedTools"), false);
232	  assert.ok(claudeWrite.args.some((arg) => arg.includes("Edit") && arg.includes("Bash")));
233	
234	  // OpenCode defaults to edit/bash "allow"; readonly must override via OPENCODE_PERMISSION.
235	  const opencode = buildRunnerInvocation({ kind: "opencode", toolsPolicy: "readonly" }, "/tmp/packet.md", "/repo");
236	  assert.deepEqual(JSON.parse(opencode.env.OPENCODE_PERMISSION), { edit: "deny", bash: "deny" });
237	  const opencodeWrite = buildRunnerInvocation({ kind: "opencode", toolsPolicy: "workspace-write" }, "/tmp/packet.md", "/repo");
238	  assert.equal(opencodeWrite.env?.OPENCODE_PERMISSION, undefined);
239	
240	  // Every engine child carries the nesting marker.
241	  for (const kind of ["pi", "claude-code", "codex", "opencode"]) {
242	    const invocation = buildRunnerInvocation({ kind, toolsPolicy: "readonly" }, "/tmp/packet.md", "/repo");
243	    assert.equal(invocation.env?.CONSENSFLOW_CHILD, "1", `${kind}: CONSENSFLOW_CHILD`);
